const spontaneous = j.spontaneous === true;
return [{ json: {
  offer_id: spontaneous ? null : (j.offer_id ?? null),
  spontaneous,
  title: spontaneous ? 'Candidature spontanée' : (j.title||''),
  company: j.company||'',
  location: j.location||'',
  description: spontaneous ? ('CANDIDATURE SPONTANÉE — aucune offre publiée. Choisis IMPÉRATIVEMENT le template "candidature-spontanee" et rédige une accroche disant pourquoi CETTE entreprise (secteur, valeurs, produits). Infos connues: ' + (j.description||'(peu d info)')) : (j.description||''),
  company_info: j.company_info||'',
} }];

